 193→/// Map a JSON value to a Go type string.
 194→fn go_type_from_value(value: &serde_json::Value) -> String {
 195→    // Check for __complex_type tagged objects first
 196→    if let Some(obj) = value.as_object()
 197→        && let Some(tag) = obj.get("__complex_type").and_then(|t| t.as_str())
 198→    {
 199→        return go_type_from_complex(tag);
 200→    }
 201→    match value {
 202→        serde_json::Value::String(_) => "string".to_string(),
 203→        serde_json::Value::Bool(_) => "bool".to_string(),
 204→        serde_json::Value::Number(n) => {
 205→            if n.is_f64() && n.to_string().contains('.') {
 206→                "float64".to_string()
 207→            } else {
 208→                "int".to_string()
 209→            }
 210→        }
 211→        serde_json::Value::Null => "interface{}".to_string(),
 212→        serde_json::Value::Array(_) => "interface{}".to_string(),
 213→        serde_json::Value::Object(_) => "interface{}".to_string(),
 214→    }
 215→}
 216→
 217→/// Map a complex type tag to its Go type name.
 218→fn go_type_from_complex(tag: &str) -> String {
 219→    match tag {
 220→        "date" | "date_time" => "time.Time".to_string(),
 221→        "duration" => "time.Duration".to_string(),
 222→        "reg_exp" => "*regexp.Regexp".to_string(),
 223→        "big_int" => "*big.Int".to_string(),
 224→        "big_decimal" => "*big.Float".to_string(),
 225→        "url" => "*url.URL".to_string(),
 226→        "ip_address" => "net.IP".to_string(),
 227→        "error" => "error".to_string(),
 228→        "rune" => "rune".to_string(),
 229→        "go_byte" => "byte".to_string(),
 230→        _ => "interface{}".to_string(),
 231→    }
 232→}
