 234→/// Format a JSON value as a Go literal.
 235→///
 236→/// Detects `__complex_type` tagged objects and emits constructor calls.
 237→fn format_go_value(value: &serde_json::Value) -> String {
 238→    if let Some(go) = try_format_complex_go(value) {
 239→        return go;
 240→    }
 241→    match value {
 242→        serde_json::Value::String(s) => format!("\"{}\"", s.replace('\\', "\\\\").replace('"', "\\\"")),
 243→        serde_json::Value::Null => "nil".to_string(),
 244→        serde_json::Value::Bool(b) => b.to_string(),
 245→        serde_json::Value::Number(n) => n.to_string(),
 246→        other => format!("/* unsupported: {} */nil", other),
 247→    }
 248→}
 249→
 250→/// Try to format a `__complex_type` tagged JSON object as a Go constructor.
 251→/// Returns `None` if the value is not a tagged complex type.
 252→fn try_format_complex_go(value: &serde_json::Value) -> Option<String> {
 253→    let obj = value.as_object()?;
 254→    let tag = obj.get("__complex_type")?.as_str()?;
 255→    match tag {
 256→        "date" | "date_time" => {
 257→            let v = obj.get("value")?;
 258→            Some(format!("time.UnixMilli({})", v))
 259→        }
 260→        "duration" => {
 261→            let ms = obj.get("ms").or_else(|| obj.get("value"))?;
 262→            Some(format!("time.Duration({}) * time.Millisecond", ms))
 263→        }
 264→        "reg_exp" => {
 265→            let source = obj.get("source")?.as_str()?;
 266→            let escaped = source.replace('\\', "\\\\").replace('"', "\\\"");
 267→            Some(format!("regexp.MustCompile(\"{escaped}\")"))
 268→        }
 269→        "big_int" => {
 270→            let v = obj.get("value")?.as_str()?;
 271→            Some(format!("func() *big.Int {{ n, _ := new(big.Int).SetString(\"{v}\", 10); return n }}()"))
 272→        }
 273→        "url" => {
 274→            let v = obj.get("value")?.as_str()?;
 275→            let escaped = v.replace('"', "\\\"");
 276→            Some(format!("func() *url.URL {{ u, _ := url.Parse(\"{escaped}\"); return u }}()"))
 277→        }
 278→        "error" => {
 279→            let msg = obj.get("message").and_then(|m| m.as_str()).unwrap_or("");
 280→            let escaped = msg.replace('"', "\\\"");
 281→            Some(format!("errors.New(\"{escaped}\")"))
 282→        }
 283→        "uuid" => {
 284→            let v = obj.get("value")?.as_str()?;
 285→            Some(format!("/* uuid */ \"{v}\""))
 286→        }
 287→        "ip_address" => {
 288→            let v = obj.get("value")?.as_str()?;
 289→            Some(format!("net.ParseIP(\"{v}\")"))
 290→        }
 291→        "rune" => {
 292→            let v = obj.get("value")?.as_str()?;
 293→            if let Some(ch) = v.chars().next() {
 294→                Some(format!("'{ch}'"))
 295→            } else {
 296→                Some("0".to_string())
 297→            }
 298→        }
 299→        "go_byte" => {
 300→            let v = obj.get("value")?;
 301→            Some(format!("byte({})", v))
 302→        }
 303→        _ => None,
 304→    }
 305→}
