 307→/// Return the Go zero value for a type name.
 308→fn go_zero_value(type_name: &str) -> String {
 309→    match type_name {
 310→        "string" => "\"\"".to_string(),
 311→        "int" => "0".to_string(),
 312→        "float64" => "0.0".to_string(),
 313→        "bool" => "false".to_string(),
 314→        _ => "nil".to_string(),
 315→    }
 316→}
