 353→/// Build a descriptive test name from a behavior.
 354→fn build_test_name(behavior: &Behavior) -> String {
 355→    let inputs = format_args_short(&behavior.input_args);
 356→
 357→    if let Some(ref error) = behavior.thrown_error {
 358→        return format!(
 359→            "throws {} for input ({})",
 360→            escape_single_quotes(&error.message),
 361→            inputs
 362→        );
 363→    }
 364→
 365→    match &behavior.return_value {
 366→        Some(val) => format!(
 367→            "returns {} for input ({})",
 368→            format_value_short(val),
 369→            inputs
 370→        ),
 371→        None => format!("returns undefined for input ({inputs})"),
 372→    }
 373→}
 374→
 375→/// Build the body of an `it` block.
 376→fn build_test_body(function_name: &str, behavior: &Behavior) -> String {
 377→    let args = behavior
 378→        .input_args
 379→        .iter()
 380→        .map(format_value)
 381→        .collect::<Vec<_>>()
 382→        .join(", ");
 383→
 384→    let mut body = String::new();
 385→
 386→    if behavior.thrown_error.is_some() {
 387→        body.push_str(&format!(
 388→            "    expect(() => {function_name}({args})).toThrow();\n"
 389→        ));
 390→    } else {
 391→        let expected = match &behavior.return_value {
 392→            Some(val) => format_value(val),
 393→            None => "undefined".to_string(),
 394→        };
 395→        body.push_str(&format!(
 396→            "    const result = {function_name}({args});\n"
 397→        ));
 398→        body.push_str(&format!("    expect(result).toEqual({expected});\n"));
 399→    }
 400→
 401→    body
 402→}
