509→                    ci.invariant.description,
510→                    ci.confidence,
511→                    ci.satisfied_count,
512→                    ci.total_count,
513→                ));
514→            }
515→            out.push('\n');
516→        }
517→
518→        // Examples
519→        out.push_str(&format!(
520→            "**Example** ({} execution(s) observed):\n",
