    let current_names: HashSet<String> =
        ["fn1", "fn2"].iter().map(|s| s.to_string()).collect();

    let merged = merge_file_spec_bundles(&existing, &[], &current_names);
    assert_eq!(merged.functions.len(), 2);
}

