                    path: vec![],
                },
            },
            target: InvariantTarget::Input,
            label: "input is never null".to_string(),
            confidence: 1.0,
            satisfied_count: 10,
            total_count: 10,
        }];
        spec.classes[0].invariants = vec![ClassifiedInvariant {
            invariant: Invariant {
                description: "x > 0".to_string(),
